     2→//!
     3→//! This module wraps the CaptureEngine and PipelineCore to provide a streaming
     4→//! CaptureAdapter implementation for live network capture.
     5→
     6→use crate::{CaptureConfig, CaptureEngine, CaptureError};
     7→use prb_core::{CaptureAdapter, CoreError, DebugEvent};
     8→use prb_pcap::{create_registry_with_builtins, PipelineCore, TlsStreamProcessor};
     9→use std::collections::VecDeque;
    10→use std::time::Duration;
    11→
    12→/// Live capture adapter that implements CaptureAdapter for streaming packet sources.
    13→///
    14→/// This adapter combines a CaptureEngine (which reads packets from a network interface)
    15→/// with a PipelineCore (which normalizes, reassembles, and decrypts packets into DebugEvents).
    16→///
    17→/// # Architecture
    18→///
    19→/// The CaptureEngine runs in a dedicated OS thread, continuously reading packets from
    20→/// libpcap and delivering them over a bounded channel. The adapter pulls from this channel
    21→/// and feeds packets through the PipelineCore incrementally.
    22→///
    23→/// # Example
    24→///
    25→/// ```no_run
    26→/// use prb_capture::{CaptureConfig, LiveCaptureAdapter};
    27→/// use prb_core::CaptureAdapter;
    28→///
    29→/// let config = CaptureConfig::new("lo0")
    30→///     .with_filter("tcp port 8080");
    31→///
    32→/// let mut adapter = LiveCaptureAdapter::new(config).unwrap();
    33→/// adapter.start().unwrap();
    34→///
    35→/// // Consume events as they arrive
    36→/// for event in adapter.ingest() {
    37→///     println!("Event: {:?}", event);
    38→/// }
    39→/// ```
    40→pub struct LiveCaptureAdapter {
    41→    engine: CaptureEngine,
    42→    core: PipelineCore,
    43→    event_buffer: VecDeque<Result<DebugEvent, CoreError>>,
    44→    origin: String,
    45→    linktype: u32,
    46→    started: bool,
    47→}
    48→
    49→impl LiveCaptureAdapter {
    50→    /// Creates a new live capture adapter with the given configuration.
    51→    ///
    52→    /// # Arguments
    53→    /// * `config` - Capture configuration specifying interface, filter, TLS keys, etc.
    54→    ///
    55→    /// # Errors
    56→    /// Returns an error if TLS keylog file cannot be loaded.
    57→    pub fn new(config: CaptureConfig) -> Result<Self, CaptureError> {
